#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j;

    for (int offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        // lud_diagonal equivalent
        {
            float shadow[BLOCK_SIZE * BLOCK_SIZE];
            int tx;

            // Load diagonal block into shadow
            #pragma omp parallel for private(tx, i) shared(m, shadow, matrix_dim, offset)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset)*matrix_dim + offset + tx;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    shadow[i * BLOCK_SIZE + tx] = m[array_offset];
                    array_offset += matrix_dim;
                }
            }

            // Synchronize threads
            #pragma omp barrier

            for (i = 0; i < BLOCK_SIZE - 1; i++) {
                #pragma omp parallel for private(tx, j) shared(shadow, i)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    if (tx > i) {
                        for (j = 0; j < i; j++) {
                            shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                        }
                        shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
                    }
                }
                #pragma omp barrier

                #pragma omp parallel for private(tx, j) shared(shadow, i)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    if (tx > i) {
                        for (j = 0; j < i + 1; j++) {
                            shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                        }
                    }
                }
                // Removed barrier here to avoid nested barrier error
            }
            // Add a barrier after the loop to synchronize threads
            #pragma omp barrier

            // Write back to m
            #pragma omp parallel for private(tx, i) shared(m, shadow, matrix_dim, offset)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + 1) * matrix_dim + offset + tx;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset] = shadow[i * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }
        }

        // lud_perimeter equivalent
        {
            float dia[BLOCK_SIZE * BLOCK_SIZE];
            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];
            int bx, tx, idx;
            int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

            if (num_blocks > 0) {
                int total_threads = 2 * BLOCK_SIZE * num_blocks;

                #pragma omp parallel for private(tx, bx, idx) shared(m, dia, peri_row, peri_col, matrix_dim, offset, num_blocks)
                for (int thread_id = 0; thread_id < total_threads; thread_id++) {
                    bx = thread_id / (2 * BLOCK_SIZE);
                    tx = thread_id % (2 * BLOCK_SIZE);

                    if (tx < BLOCK_SIZE) {
                        idx = tx;
                        int array_offset = offset * matrix_dim + offset;
                        for (int i = 0; i < BLOCK_SIZE / 2; i++) {
                            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }

                        array_offset = offset * matrix_dim + offset;
                        for (int i = 0; i < BLOCK_SIZE; i++) {
                            peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx - BLOCK_SIZE;
                        int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                        for (int i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }

                        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                        for (int i = 0; i < BLOCK_SIZE; i++) {
                            peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }

                #pragma omp barrier

                // Compute peri_row
                #pragma omp parallel for private(tx, i, j, idx) shared(peri_row, dia)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    idx = tx;
                    for (i = 1; i < BLOCK_SIZE; i++) {
                        for (j = 0; j < i; j++) {
                            peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                        }
                    }
                }

                // Compute peri_col
                #pragma omp parallel for private(tx, i, j, idx) shared(peri_col, dia)
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    idx = tx;
                    for (int i = 0; i < BLOCK_SIZE; i++) {
                        for (j = 0; j < i; j++) {
                            peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                        }
                        peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                    }
                }

                #pragma omp barrier

                // Write back peri_row and peri_col to m
                #pragma omp parallel for private(tx, i, idx) shared(m, peri_row, peri_col, matrix_dim, offset, num_blocks)
                for (int thread_id = 0; thread_id < total_threads; thread_id++) {
                    bx = thread_id / (2 * BLOCK_SIZE);
                    tx = thread_id % (2 * BLOCK_SIZE);

                    if (tx < BLOCK_SIZE) {
                        idx = tx;
                        int array_offset = (offset + 1) * matrix_dim + offset;
                        array_offset += (bx + 1) * BLOCK_SIZE;
                        for (i = 1; i < BLOCK_SIZE; i++) {
                            m[array_offset + idx] = peri_row[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx - BLOCK_SIZE;
                        int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                        for (i = 0; i < BLOCK_SIZE; i++) {
                            m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }
            }
        }

        // lud_internal equivalent
        {
            int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
            if (num_blocks > 0) {
                float peri_row[BLOCK_SIZE * BLOCK_SIZE];
                float peri_col[BLOCK_SIZE * BLOCK_SIZE];

                #pragma omp parallel for collapse(2) private(i, j) shared(m, peri_row, peri_col, matrix_dim, offset, num_blocks)
                for (int by = 0; by < num_blocks; by++) {
                    for (int bx = 0; bx < num_blocks; bx++) {
                        int tx, ty;
                        // Load peri_row and peri_col
                        #pragma omp parallel for private(tx, ty) shared(m, peri_row, peri_col, matrix_dim, offset, bx, by)
                        for (ty = 0; ty < BLOCK_SIZE; ty++) {
                            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                                int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                                int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
                                peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                                peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                            }
                        }

                        // Removed barrier here to avoid nested barrier error

                        // Compute sum and update m
                        #pragma omp parallel for private(tx, ty, i) shared(m, peri_row, peri_col, matrix_dim, offset, bx, by)
                        for (ty = 0; ty < BLOCK_SIZE; ty++) {
                            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                                float sum = 0.0f;
                                for (i = 0; i < BLOCK_SIZE; i++) {
                                    sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                                }
                                int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                                int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
                                #pragma omp atomic
                                m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                            }
                        }
                    }
                }
            }
        }
    }
}
